namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new OrderService();
    }

    [TestClass]
    public sealed class CreateOrder
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void ShouldReturnOrderWithCorrectCustomerId()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
            };

            var order = _sut.CreateOrder("cust-1", items);

            Assert.AreEqual("cust-1", order.CustomerId);
        }

        [TestMethod]
        public void ShouldCalculateTotalFromItemPricesAndQuantities()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
                new() { ProductName = "Gadget", Price = 5.50m, Quantity = 3 }
            };

            var order = _sut.CreateOrder("cust-1", items);

            Assert.AreEqual(36.50m, order.Total);
        }

        [TestMethod]
        public void ShouldAssignUniqueId()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
            };

            var order = _sut.CreateOrder("cust-1", items);

            Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        }

        [TestMethod]
        public void ShouldAssignDistinctIdsForDifferentOrders()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
            };

            var order1 = _sut.CreateOrder("cust-1", items);
            var order2 = _sut.CreateOrder("cust-1", items);

            Assert.AreNotEqual(order1.Id, order2.Id);
        }

        [TestMethod]
        public void ShouldSetCreatedAtToRecentUtcTime()
        {
            var before = DateTime.UtcNow;
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 1.00m, Quantity = 1 }
            };

            var order = _sut.CreateOrder("cust-1", items);

            var after = DateTime.UtcNow;
            Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
        }

        [TestMethod]
        public void ShouldStoreItemsOnOrder()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 },
                new() { ProductName = "Gadget", Price = 5.00m, Quantity = 2 }
            };

            var order = _sut.CreateOrder("cust-1", items);

            Assert.AreEqual(2, order.Items.Count);
            Assert.AreEqual("Widget", order.Items[0].ProductName);
            Assert.AreEqual("Gadget", order.Items[1].ProductName);
        }

        [TestMethod]
        public void ShouldThrowArgumentNullExceptionWhenCustomerIdIsNull()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
            };

            Assert.ThrowsExactly<ArgumentNullException>(
                () => _sut.CreateOrder(null!, items));
        }

        [TestMethod]
        public void ShouldThrowArgumentNullExceptionWhenItemsIsNull()
        {
            Assert.ThrowsExactly<ArgumentNullException>(
                () => _sut.CreateOrder("cust-1", null!));
        }

        [TestMethod]
        public void ShouldThrowInvalidOperationExceptionWhenItemsIsEmpty()
        {
            Assert.ThrowsExactly<InvalidOperationException>(
                () => _sut.CreateOrder("cust-1", []));
        }

        [TestMethod]
        public void ShouldMakeOrderRetrievableAfterCreation()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 }
            };

            var created = _sut.CreateOrder("cust-1", items);
            var retrieved = _sut.GetOrder(created.Id);

            Assert.AreSame(created, retrieved);
        }
    }

    [TestClass]
    public sealed class GetOrder
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void ShouldReturnNullWhenOrderDoesNotExist()
        {
            var result = _sut.GetOrder("nonexistent-id");

            Assert.IsNull(result);
        }

        [TestMethod]
        public void ShouldReturnCorrectOrderById()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };
            var order = _sut.CreateOrder("cust-1", items);

            var result = _sut.GetOrder(order.Id);

            Assert.IsNotNull(result);
            Assert.AreEqual(order.Id, result.Id);
        }
    }

    [TestClass]
    public sealed class GetOrdersByCustomer
    {
        private OrderService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new OrderService();
        }

        [TestMethod]
        public void ShouldReturnEmptyListWhenCustomerHasNoOrders()
        {
            var result = _sut.GetOrdersByCustomer("cust-unknown");

            Assert.AreEqual(0, result.Count);
        }

        [TestMethod]
        public void ShouldReturnAllOrdersForACustomer()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };
            _sut.CreateOrder("cust-1", items);
            _sut.CreateOrder("cust-1", items);
            _sut.CreateOrder("cust-2", items);

            var result = _sut.GetOrdersByCustomer("cust-1");

            Assert.AreEqual(2, result.Count);
            Assert.IsTrue(result.All(o => o.CustomerId == "cust-1"));
        }

        [TestMethod]
        public void ShouldNotReturnOrdersBelongingToOtherCustomers()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 }
            };
            _sut.CreateOrder("cust-1", items);
            _sut.CreateOrder("cust-2", items);

            var result = _sut.GetOrdersByCustomer("cust-2");

            Assert.AreEqual(1, result.Count);
            Assert.AreEqual("cust-2", result[0].CustomerId);
        }
    }
}

